/*
 * MPI Collective Communication Example: Broadcast
 * Demonstrates MPI_Bcast to distribute data from root to all processes
 * 
 * Compilation: mpicc -o broadcast broadcast.c
 * Execution: mpirun -np 4 ./broadcast
 */

#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>

#define ROOT_PROCESS 0

int main(int argc, char *argv[]) {
 int rank, size;
 int data; // Data to be broadcast
 int local_square; // Each process computes square of received data

 // Initialize MPI environment
 MPI_Init(&argc, &argv);

 // Get process rank and total number of processes
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 // Only root process initializes the data
 if (rank == ROOT_PROCESS) {
 data = 42;
 printf("Root process %d: Initialized data = %d\n", rank, data);
 } else {
 data = 0; // Other processes initialize with placeholder
 }

 // Synchronize all processes before broadcast
 MPI_Barrier(MPI_COMM_WORLD);

 // Broadcast data from root (process 0) to all processes
 // After this call, all processes will have the same value in 'data'
 MPI_Bcast(&data, // Buffer pointer
 1, // Number of elements
 MPI_INT, // Data type
 ROOT_PROCESS, // Root process rank
 MPI_COMM_WORLD); // Communicator

 // Each process computes its local result
 local_square = data * data;

 // Print results from all processes
 printf("Process %d: Received data = %d, computed square = %d\n", 
 rank, data, local_square);

 // Demonstrate gather - collect all squares back to root
 int *all_squares = NULL;
 if (rank == ROOT_PROCESS) {
 all_squares = malloc(size * sizeof(int));
 }

 MPI_Gather(&local_square, // Send buffer
 1, // Send count
 MPI_INT, // Send type
 all_squares, // Receive buffer (only root needs this)
 1, // Receive count per process
 MPI_INT, // Receive type
 ROOT_PROCESS, // Root process
 MPI_COMM_WORLD);

 // Root process prints all gathered values
 if (rank == ROOT_PROCESS) {
 printf("\nRoot gathered all squares: ");
 for (int i = 0; i < size; i++) {
 printf("%d ", all_squares[i]);
 }
 printf("\n");
 free(all_squares);
 }

 // Finalize MPI environment
 MPI_Finalize();

 return 0;
}

/*
 * MPI Parallel Reduction Example: Computing Global Sum
 * Demonstrates MPI_Reduce to combine values from all processes
 * 
 * Each process computes a partial sum, then reduction combines them
 * Compilation: mpicc -o reduction reduction.c
 * Execution: mpirun -np 4 ./reduction
 */

#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>

#define ARRAY_SIZE 1000
#define ROOT_PROCESS 0

// Function to compute partial sum for a portion of array
long compute_partial_sum(int start, int end) {
 long sum = 0;
 for (int i = start; i < end; i++) {
 sum += i; // Simple computation: sum of indices
 }
 return sum;
}

int main(int argc, char *argv[]) {
 int rank, size;
 int local_start, local_end;
 long local_sum = 0;
 long global_sum = 0;

 // Initialize MPI
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 // Calculate work distribution: divide array among processes
 int chunk_size = ARRAY_SIZE / size;
 int remainder = ARRAY_SIZE % size;

 // Distribute remainder among first few processes
 if (rank < remainder) {
 local_start = rank * (chunk_size + 1);
 local_end = local_start + chunk_size + 1;
 } else {
 local_start = rank * chunk_size + remainder;
 local_end = local_start + chunk_size;
 }

 // Each process computes its local partial sum
 local_sum = compute_partial_sum(local_start, local_end);

 printf("Process %d: Computed local_sum = %ld (range: %d to %d)\n",
 rank, local_sum, local_start, local_end);

 // Synchronize before reduction
 MPI_Barrier(MPI_COMM_WORLD);

 // Reduce all local sums to global sum at root process
 // MPI_Reduce combines values using specified operation (MPI_SUM)
 MPI_Reduce(&local_sum, // Send buffer
 &global_sum, // Receive buffer (valid at root)
 1, // Number of elements
 MPI_LONG, // Data type
 MPI_SUM, // Reduction operation
 ROOT_PROCESS, // Root process
 MPI_COMM_WORLD);

 // Allreduce: get global sum available to ALL processes
 long all_global_sum = 0;
 MPI_Allreduce(&local_sum,
 &all_global_sum,
 1,
 MPI_LONG,
 MPI_SUM,
 MPI_COMM_WORLD);

 // Root process prints final result
 if (rank == ROOT_PROCESS) {
 // Verify: sum of 0 to 999 = 999*1000/2 = 499500
 long expected = (long)(ARRAY_SIZE - 1) * ARRAY_SIZE / 2;
 printf("\n=== RESULTS ===\n");
 printf("Global sum (at root): %ld\n", global_sum);
 printf("Expected sum: %ld\n", expected);
 printf("Verification: %s\n", 
 global_sum == expected ? "PASSED" : "FAILED");
 }

 // All processes print the allreduce result
 printf("Process %d: Allreduce result = %ld\n", rank, all_global_sum);

 // Demonstrate other reduction operations
 long local_max = local_sum;
 long global_max = 0;
 MPI_Reduce(&local_max, &global_max, 1, MPI_LONG, MPI_MAX, 
 ROOT_PROCESS, MPI_COMM_WORLD);

 if (rank == ROOT_PROCESS) {
 printf("Maximum local sum: %ld\n", global_max);
 }

 MPI_Finalize();
 return 0;
}
